// === 三层 DMA 循环缓冲区架构接口定义 ===
// 应用层只看到这三个函数

#ifndef DMA_RINGBUF_H
#define DMA_RINGBUF_H

#include <stdint.h>
#include <stdbool.h>
#include <stddef.h>

/* 环形缓冲区——应用层通过此接口与 DMA 交互 */
typedef struct {
    uint8_t *buf;           /* 缓冲区指针（必须在 DMA 可访问的内存区）*/
    uint16_t  size;         /* 缓冲区大小（必须是 2 的幂，便于位运算取模）*/
    uint16_t  head;         /* 读指针（应用层消费数据时递增）*/
    uint16_t  tail;         /* 写指针（DMA 中断回调中递增）*/
    volatile uint16_t count; /* 缓冲区中有效字节数（volatile 因为 DMA ISR 修改）*/
} dma_ringbuf_t;

/* 第 1 层：硬件抽象——由底层驱动初始化 */
int  dma_ringbuf_init(dma_ringbuf_t *rb, uint8_t *buf, uint16_t size);

/* 第 2 层：缓冲区管理——由 DMA 中断回调调用 */
void dma_ringbuf_push(dma_ringbuf_t *rb, const uint8_t *data, uint16_t len);

/* 第 3 层：应用接口——应用层只看到这些函数 */
uint16_t dma_ringbuf_available(const dma_ringbuf_t *rb);
uint16_t dma_ringbuf_drain(dma_ringbuf_t *rb, uint8_t *out, uint16_t max_len);
bool     dma_ringbuf_is_full(const dma_ringbuf_t *rb);

#endif

/* === 架构说明 ===
 * 应用层调用:
 *   dma_ringbuf_init(&uart4_rb, uart4_rx_buf, 512);
 *   dma_ringbuf_start();                    // 启动 DMA2_Stream5 + UART4_RX
 *   ...
 *   uint16_t n = dma_ringbuf_drain(&uart4_rb, my_buf, 64);
 *   // n <= 64, 永远不会超过 64
 */

/* === UART4 + DMA2_Stream5 环形缓冲区消费回调 ===
 * 平台: STM32F4xx / STM32L4xx (HAL 库)
 * DMA 通道: DMA2_Stream5, Channel 4 (UART4_RX)
 * 缓冲区: 512 字节, Circular 模式
 * 中断优先级: DMA2_Stream5 = 0 (最高), UART4 = 2
 */

#define UART4_DMA_BUF_SIZE  512
static uint8_t uart4_dma_buf[UART4_DMA_BUF_SIZE];
extern dma_ringbuf_t uart4_rb;

/* DMA 回调：传输过半 (HT) 或 传输完成 (TC) 时调用 */
void HAL_UARTEx_Receive_DMA_FullReceiveCallback(UART_HandleTypeDef *huart)
{
    if (huart->Instance != UART4) return;

    /* 第 1 步：计算 DMA 已写入的字节数 */
    /* DMA2_Stream5->NDTR 是剩余传输计数，递减到 0 后重载 */
    uint16_t dma_remaining = DMA2->Stream5->NDTR;
    uint16_t dma_written = UART4_DMA_BUF_SIZE - dma_remaining;

    /* 第 2 步：将 DMA 写入的新数据推入环形缓冲区 */
    uint16_t consumed = 0;
    while (consumed < dma_written) {
        /* 环形缓冲区还有空间吗？ */
        if (uart4_rb.count >= uart4_rb.size - 1) {
            /* 缓冲区满了——丢弃最老的数据 */
            uart4_rb.tail = (uart4_rb.tail + 1) & (uart4_rb.size - 1);
            uart4_rb.count--;
        }
        /* 拷贝一个字节 */
        uart4_rb.buf[uart4_rb.tail] = uart4_dma_buf[consumed];
        uart4_rb.tail = (uart4_rb.tail + 1) & (uart4_rb.size - 1);
        uart4_rb.count++;
        consumed++;
    }

    /* 第 3 步：清除 DMA 中断标志（HAL 通常已自动清除）*/
    // DMA2_Stream5->IFCR = DMA_IFCR_CHTIF | DMA_IFCR_CTCIF;
}

// === 陷阱演示与修复 ===

// === 陷阱 1：DMA 缓冲区不在 DMA 可访问的内存区 ===
// ❌ 错误：缓冲区放在普通全局变量区
static uint8_t uart4_rx_buf[512];  /* 可能在 D2 SRAM 或 Flash 中 */

// ✅ 修复：使用 __attribute__((section)) 指定到 DMA 可访问的内存区
/* STM32H7: DMA2 可访问 D1 AXI SRAM (0x24000000) */
__attribute__((section(".dma_buffer")))
static uint8_t uart4_rx_buf[512];

// === 陷阱 2：缓冲区大小不是 2 的幂 ===
// ❌ 错误：size=500，取模运算慢
#define BUF_SIZE 500
uint16_t idx = (idx + 1) % BUF_SIZE;  /* 生成 div 指令！*/

// ✅ 修复：size=512，位运算取模
#define BUF_SIZE 512
uint16_t idx = (idx + 1) & (BUF_SIZE - 1);  /* 生成 and 指令！*/

// === 陷阱 3：count 不是 volatile ===
// ❌ 错误：主循环读 count 时被编译器优化
uint16_t dma_ringbuf_available(const dma_ringbuf_t *rb) {
    return rb->count;  /* 编译器可能只读一次，之后用寄存器缓存 */
}

