// === 陷阱 4：DMA 回调中没有重新启动 DMA ===
// ❌ 错误：只消费数据，不调用 HAL_UART_Receive_DMA()
void HAL_UART_RxCpltCallback(UART_HandleTypeDef *huart) {
    dma_ringbuf_drain(&uart4_rb, temp_buf, 64);
    /* 忘了重新启动 DMA！第二圈数据全部丢失 */
}

// ✅ 修复：回调末尾重新启动 DMA
void HAL_UART_RxCpltCallback(UART_HandleTypeDef *huart) {
    dma_ringbuf_drain(&uart4_rb, temp_buf, 64);
    HAL_UART_Receive_DMA(huart, uart4_dma_buf, UART4_DMA_BUF_SIZE);
}

// === 重构前：裸机 DMA 回调——80 行大泥球 ===
// ❌ 一个函数做了：寄存器读取 + 数据拷贝 + 协议解析 + CRC + 日志

void HAL_UARTEx_Receive_DMA_FullReceiveCallback(UART_HandleTypeDef *huart)
{
    if (huart->Instance != UART4) return;

    /* 1. 读取 DMA 寄存器 */
    uint16_t ndtr = DMA2->Stream5->NDTR;
    uint16_t written = 512 - ndtr;

    /* 2. 数据拷贝——内联拷贝，没有边界检查 */
    for (int i = 0; i < written; i++) {
        rx_buffer[write_idx++] = uart4_dma_buf[i];  /* 没有边界检查！*/
        if (write_idx >= 512) write_idx = 0;        /* 简单的 wrap */
    }

    /* 3. 协议解析——在 ISR 中做这件事太危险了 */
    for (int i = 0; i < written; i++) {
        if (uart4_dma_buf[i] == 0xAA) {             /* 帧头 */
            frame_start = true;
            frame_len = 0;
        }
        if (frame_start) {
            frame_data[frame_len++] = uart4_dma_buf[i];
            if (frame_len >= 256) {                 /* 帧太长 */
                frame_start = false;
                /* CRC 校验——在 ISR 中做 CRC 校验？ */
                uint8_t crc = 0;
                for (int j = 0; j < frame_len; j++)
                    crc ^= frame_data[j];
                if (crc != frame_data[frame_len-1]) {
                    /* 错误处理——但我们在 ISR 中！ */
                    error_count++;
                }
            }
        }
    }

    /* 4. 日志打印——在 ISR 中调用 printf？！ */
    if (written > 0) {
        char log_buf[64];
        snprintf(log_buf, sizeof(log_buf), "RX:%d\n", written);
        HAL_UART_Transmit(&huart2, (uint8_t*)log_buf, strlen(log_buf), 10);
    }

    /* 5. 重新启动 DMA */
    HAL_UART_Receive_DMA(huart, uart4_dma_buf, 512);
}

// 坏味道总结：
// 1. 过长函数（120+ 行）—— Martin Fowler, 《重构》
// 2. 依恋情结——函数访问了大量全局变量（rx_buffer, write_idx, frame_*）
// 3. 在 ISR 中做 CRC 校验和 printf——严重违反嵌入式实时性原则
// 4. 没有边界检查——write_idx 可能越界
// 5. 数据和逻辑耦合——协议解析硬编码在 DMA 回调中

// === 重构后：回调只做数据搬运，处理在主循环中 ===

/* 第 1 步：环形缓冲区——可测试的数据结构 */
typedef struct {
    uint8_t *buf;
    uint16_t size;
    volatile uint16_t head;
    volatile uint16_t tail;
    volatile uint16_t count;
} dma_ringbuf_t;

/* push: 从 DMA ISR 调用，拷贝数据到环形缓冲区 */
static void ringbuf_push(dma_ringbuf_t *rb, const uint8_t *src, uint16_t len)
{
    for (uint16_t i = 0; i < len; i++) {
        if (rb->count >= rb->size) {
            /* 缓冲区满——丢弃最老的数据 */
            rb->head = (rb->head + 1) & (rb->size - 1);
            rb->count--;
        }
        rb->buf[rb->tail] = src[i];
        rb->tail = (rb->tail + 1) & (rb->size - 1);
        rb->count++;
    }
}

/* drain: 从主循环调用，消费环形缓冲区中的数据 */
static uint16_t ringbuf_drain(dma_ringbuf_t *rb, uint8_t *dst, uint16_t max_len)
{
    uint16_t available = rb->count < max_len ? rb->count : max_len;
    for (uint16_t i = 0; i < available; i++) {
        dst[i] = rb->buf[rb->head];
        rb->head = (rb->head + 1) & (rb->size - 1);
    }
    rb->count -= available;
    return available;
}

/* 第 2 步：DMA 回调——现在只有 5 行 */
void HAL_UARTEx_Receive_DMA_FullReceiveCallback(UART_HandleTypeDef *huart)
{
    if (huart->Instance != UART4) return;

    uint16_t written = UART4_DMA_BUF_SIZE - DMA2->Stream5->NDTR;
    ringbuf_push(&uart4_rb, uart4_dma_buf, written);

    HAL_UART_Receive_DMA(huart, uart4_dma_buf, UART4_DMA_BUF_SIZE);
}

/* 第 3 步：主循环中处理数据——可以安全地做 CRC、日志等 */
void app_process_uart_data(void)
{
    uint8_t frame[256];
    uint16_t n = ringbuf_drain(&uart4_rb, frame, sizeof(frame));
    if (n == 0) return;

    /* 协议解析——在主循环中，不受 ISR 时间限制 */
    parse_uart_frame(frame, n);  /* CRC、帧校验、业务逻辑 */
}
